mapper.select:
SELECT *
FROM job_application
WHERE job_id = #{jobId}
  AND student_id = #{studentId}
ORDER BY id DESC
LIMIT 1

SELECT *
FROM job_application
WHERE student_id = #{studentId}
  AND id = #{id}
LIMIT 1

SELECT *
FROM job_application
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
LIMIT 1

SELECT ja.id AS applicationId, ja.application_no AS applicationNo, ja.job_id AS jobId, ja.enterprise_id AS enterpriseId, ja.resume_id AS resumeId, ja.status AS status, ja.latest_communication_type AS latestCommunicationType, ja.latest_communication_time AS latestCommunicationTime, ja.read_by_student AS readByStudent, ja.submitted_time AS submittedTime, ja.updated_time AS updatedTime, ja.job_snapshot_json AS jobSnapshotJson, ja.enterprise_snapshot_json AS enterpriseSnapshotJson, ja.resume_snapshot_json AS resumeSnapshotJson FROM job_application ja WHERE ja.student_id = #{studentId}
AND ja.status = #{status}
AND ( JSON_UNQUOTE(JSON_EXTRACT(ja.job_snapshot_json, '$.jobTitle')) LIKE CONCAT('%', #{keyword}, '%') OR JSON_UNQUOTE(JSON_EXTRACT(ja.enterprise_snapshot_json, '$.enterpriseName')) LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY ja.updated_time DESC, ja.id DESC

SELECT ja.id AS applicationId, ja.application_no AS applicationNo, ja.job_id AS jobId, ja.resume_id AS resumeId, ja.status AS status, ja.match_score AS matchScore, ja.latest_communication_type AS latestCommunicationType, ja.latest_communication_time AS latestCommunicationTime, ja.submitted_time AS submittedTime, ja.updated_time AS updatedTime, ja.job_snapshot_json AS jobSnapshotJson, ja.resume_snapshot_json AS resumeSnapshotJson, s.id AS studentId, s.student_number AS studentNumber, COALESCE(u.real_name, u.nickname) AS studentName FROM job_application ja LEFT JOIN education_user_db.students s ON s.id = ja.student_id LEFT JOIN education_user_db.users u ON u.id = s.user_id WHERE ja.enterprise_id = #{enterpriseId}
AND ja.job_id = #{jobId}
AND ja.status = #{status}
AND ( COALESCE(u.real_name, u.nickname) LIKE CONCAT('%', #{keyword}, '%') OR s.student_number LIKE CONCAT('%', #{keyword}, '%') OR JSON_UNQUOTE(JSON_EXTRACT(ja.resume_snapshot_json, '$.resumeTitle')) LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY ja.updated_time DESC, ja.id DESC

mapper.update:
UPDATE job_application
SET read_by_student = #{readByStudent},
    updated_time = NOW()
WHERE id = #{id}
  AND student_id = #{studentId}

UPDATE job_application
SET read_by_enterprise = #{readByEnterprise},
    updated_time = NOW()
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}

UPDATE job_application
SET status = #{status},
    remark = #{remark},
    read_by_student = #{readByStudent},
    updated_time = #{updatedTime}
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}

UPDATE job_application
SET status = #{status},
    read_by_enterprise = #{readByEnterprise},
    updated_time = #{updatedTime}
WHERE id = #{id}
  AND student_id = #{studentId}

